+		}
+	case map[interface{}]interface{}:
+		for key := range typed {
+			if keyName, ok := key.(string); ok {
+				keys[keyName] = true
+			}
+		}
+	}
+
+	return keys
+}
+
+func mapValue(value any) map[string]any {
+	switch typed := value.(type) {
+	case map[string]any:
+		return typed
+	case map[interface{}]interface{}:
+		result := map[string]any{}
+		for key, val := range typed {
+			keyName, ok := key.(string)
+			if !ok {
+				continue
+			}
+			result[keyName] = val
+		}
+		return result
+	default:
+		return nil
+	}
+}
